import React, { useEffect, useState } from 'react';
import api from '../utils/api';

export default function MyBorrows() {
  const [borrows, setBorrows] = useState<any[]>([]);
  const [requests, setRequests] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [tab, setTab] = useState<'borrows'|'requests'>('requests');

  useEffect(() => {
    Promise.all([
      api.get('/borrows/my'),
      api.get('/borrows/my-requests')
    ]).then(([b, r]) => {
      setBorrows(b.data.data || []);
      setRequests(r.data.data || []);
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  const SBG: any = { borrowed: '#fef3c7', returned: '#d1fae5', overdue: '#fee2e2' };
  const SBC: any = { borrowed: '#d97706', returned: '#059669', overdue: '#dc2626' };
  const RBG: any = { pending: '#fef3c7', approved: '#d1fae5', rejected: '#fee2e2' };
  const RBC: any = { pending: '#d97706', approved: '#059669', rejected: '#dc2626' };

  const pendingCount = requests.filter(r => r.status === 'pending').length;

  return (
    <div className="page-enter" style={{ padding: 32 }}>
      <div style={{ marginBottom: 24 }}>
        <h1 style={{ fontFamily: "'Playfair Display',serif", fontSize: 28, fontWeight: 700 }}>My Library</h1>
        <p style={{ color: '#9ca3af', fontSize: 13, marginTop: 4 }}>Your borrow history and requests</p>
      </div>

      {/* Tabs */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 24 }}>
        <button onClick={() => setTab('requests')}
          style={{ padding: '9px 20px', background: tab === 'requests' ? '#1a1a2e' : '#fff', color: tab === 'requests' ? '#fff' : '#6b7280', border: tab === 'requests' ? 'none' : '1px solid #e8e0d0', borderRadius: 10, fontSize: 13, fontWeight: 500, cursor: 'pointer', fontFamily: 'inherit', display: 'flex', alignItems: 'center', gap: 6 }}>
          📋 My Requests
          {pendingCount > 0 && <span style={{ background: '#c9a84c', color: '#1a1a2e', borderRadius: 99, padding: '1px 7px', fontSize: 11, fontWeight: 700 }}>{pendingCount}</span>}
        </button>
        <button onClick={() => setTab('borrows')}
          style={{ padding: '9px 20px', background: tab === 'borrows' ? '#1a1a2e' : '#fff', color: tab === 'borrows' ? '#fff' : '#6b7280', border: tab === 'borrows' ? 'none' : '1px solid #e8e0d0', borderRadius: 10, fontSize: 13, fontWeight: 500, cursor: 'pointer', fontFamily: 'inherit' }}>
          📚 Borrowed Books
        </button>
      </div>

      {loading ? (
        <div style={{ textAlign: 'center', padding: 60, color: '#9ca3af' }}>Loading...</div>
      ) : tab === 'requests' ? (
        // Requests tab
        requests.length ? (
          <div style={{ display: 'grid', gap: 12 }}>
            {requests.map(r => (
              <div key={r.id} style={{ background: '#fff', border: '1px solid #e8e0d0', borderRadius: 14, padding: 18, display: 'flex', alignItems: 'center', gap: 16 }}>
                <div style={{ width: 44, height: 44, background: '#1a1a2e', borderRadius: 10, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 20, flexShrink: 0 }}>📗</div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 2 }}>{r.title}</div>
                  <div style={{ fontSize: 12, color: '#9ca3af' }}>{r.author}</div>
                  <div style={{ fontSize: 11, color: '#9ca3af', marginTop: 4 }}>
                    Requested: {new Date(r.request_date).toLocaleDateString('en-GB')}
                  </div>
                </div>
                <div style={{ textAlign: 'right' }}>
                  <span style={{ fontSize: 12, fontWeight: 600, padding: '4px 14px', borderRadius: 99, background: RBG[r.status], color: RBC[r.status], display: 'inline-block', textTransform: 'capitalize' }}>
                    {r.status === 'pending' ? '⏳ Pending' : r.status === 'approved' ? '✓ Approved' : '✕ Rejected'}
                  </span>
                  {r.reject_reason && (
                    <div style={{ fontSize: 11, color: '#dc2626', marginTop: 6, maxWidth: 180 }}>
                      Reason: {r.reject_reason}
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div style={{ textAlign: 'center', padding: 80, color: '#9ca3af' }}>
            <div style={{ fontSize: 52, marginBottom: 12 }}>📋</div>
            <p style={{ fontSize: 15, fontWeight: 600 }}>No requests yet</p>
            <p style={{ fontSize: 13, marginTop: 6 }}>Go to Books page and click "Request Borrow"</p>
          </div>
        )
      ) : (
        // Borrows tab
        borrows.length ? (
          <div style={{ display: 'grid', gap: 12 }}>
            {borrows.map(b => (
              <div key={b.id} style={{ background: '#fff', border: '1px solid #e8e0d0', borderRadius: 14, padding: 18, display: 'flex', alignItems: 'center', gap: 16 }}>
                <div style={{ width: 44, height: 44, background: '#1a1a2e', borderRadius: 10, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 20, flexShrink: 0 }}>📗</div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 2 }}>{b.title}</div>
                  <div style={{ fontSize: 12, color: '#9ca3af' }}>{b.author}</div>
                </div>
                <div style={{ textAlign: 'right' }}>
                  <span style={{ fontSize: 12, fontWeight: 600, padding: '4px 14px', borderRadius: 99, background: SBG[b.status] || '#f3f4f6', color: SBC[b.status] || '#6b7280', display: 'inline-block', marginBottom: 6, textTransform: 'capitalize' }}>
                    {b.status}
                  </span>
                  <div style={{ fontSize: 12, color: '#6b7280' }}>Due: {b.due_date?.split('T')[0]}</div>
                  {b.fine_amount > 0 && <div style={{ fontSize: 13, fontWeight: 700, color: '#dc2626', marginTop: 4 }}>Fine: ${Number(b.fine_amount).toFixed(2)}</div>}
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div style={{ textAlign: 'center', padding: 80, color: '#9ca3af' }}>
            <div style={{ fontSize: 52, marginBottom: 12 }}>📚</div>
            <p style={{ fontSize: 15, fontWeight: 600 }}>No books borrowed yet</p>
          </div>
        )
      )}
    </div>
  );
}
